package com.example.demo.ui;import com.example.demo.dto.AuditoriaDTO;import com.example.demo.services.AuditoriaService;import com.vaadin.flow.component.grid.Grid;import com.vaadin.flow.component.orderedlayout.VerticalLayout;import com.vaadin.flow.data.provider.DataProvider;import com.vaadin.flow.router.*;import org.springframework.data.domain.PageRequest;import org.springframework.data.domain.Sort;
@Route(value="auditoria",layout=MainLayout.class)@PageTitle("Auditoría | Franco")public class AuditoriaView extends VerticalLayout{public AuditoriaView(AuditoriaService service){addClassName("content-view");setSizeFull();Grid<AuditoriaDTO>g=new Grid<>(AuditoriaDTO.class,false);g.addColumn(AuditoriaDTO::fecha).setHeader("Fecha y hora");g.addColumn(AuditoriaDTO::usuario).setHeader("Usuario");g.addColumn(AuditoriaDTO::accion).setHeader("Acción");g.addColumn(AuditoriaDTO::entidad).setHeader("Entidad");g.addColumn(AuditoriaDTO::entidadId).setHeader("ID");g.addColumn(AuditoriaDTO::detalle).setHeader("Detalle");g.setPageSize(50);g.setItems(DataProvider.fromCallbacks(q->service.listar(PageRequest.of(q.getPage(),q.getPageSize(),Sort.by(Sort.Direction.DESC,"fecha"))).stream(),q->Math.toIntExact(service.cantidad())));add(ViewSupport.header("Auditoría"),g);expand(g);}}
